DROP TABLE IF EXISTS `cli_emr_contents`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cli_emr_contents` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `CODE` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'EMR content code',
  `EMR_HEADER_ID` int NOT NULL COMMENT 'Reference to cli_emr_headers',
  `PATIENT_ID` int NOT NULL COMMENT 'Reference to pat_patients',
  `VISIT_ID` int DEFAULT NULL COMMENT 'Reference to cli_visits',
  `CONTENT_TYPE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Type: TEXT, HTML, XML, JSON, BLOB',
  `CONTENT_FORMAT` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Format: PLAIN_TEXT, RICH_TEXT, STRUCTURED_DATA',
  `CONTENT` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Document content',
  `CONTENT_SIZE` int DEFAULT NULL COMMENT 'Content size in bytes',
  `COMPRESSION_TYPE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Compression type used',
  `ENCRYPTION_KEY_ID` int DEFAULT NULL COMMENT 'Encryption key used',
  `ENCRYPTION_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'NONE' COMMENT 'Encryption status',
  `STRUCTURED_DATA` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Structured data portion (JSON/XML)',
  `UNSTRUCTURED_CONTENT` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Unstructured content',
  `SECTIONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Document sections (JSON)',
  `ATTACHMENTS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Attachments metadata (JSON)',
  `IMAGES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Images metadata (JSON)',
  `LINKS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Internal/external links (JSON)',
  `MEDICAL_REFERENCES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Medical references (JSON)',
  `CODING_DATA` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Coding information (JSON)',
  `VALIDATION_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'VALID' COMMENT 'Validation status',
  `VALIDATION_ERRORS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Validation errors',
  `SPELL_CHECK_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'PASSED' COMMENT 'Spell check status',
  `GRAMMAR_CHECK_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'PASSED' COMMENT 'Grammar check status',
  `READABILITY_SCORE` decimal(5,2) DEFAULT NULL COMMENT 'Readability score',
  `COMPLETENESS_SCORE` decimal(5,2) DEFAULT NULL COMMENT 'Completeness score',
  `QUALITY_SCORE` decimal(5,2) DEFAULT NULL COMMENT 'Overall quality score',
  `AUTO_GENERATED` tinyint(1) DEFAULT '0' COMMENT 'Auto-generated content',
  `TEMPLATE_APPLIED` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Template applied',
  `NLP_PROCESSED` tinyint(1) DEFAULT '0' COMMENT 'NLP processed',
  `NLP_ENTITIES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'NLP extracted entities (JSON)',
  `NLP_SENTIMENT` decimal(3,2) DEFAULT NULL COMMENT 'NLP sentiment score',
  `SEARCH_INDEX` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Search index data',
  `BACKUP_LOCATION` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Content backup location',
  `MIRROR_LOCATIONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Mirror locations (JSON)',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `LAST_UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `STATUS` int NOT NULL DEFAULT '1',
  `CREATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_PROGRAM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UK_CODE` (`CODE`),
  UNIQUE KEY `UK_EMR_HEADER_ID` (`EMR_HEADER_ID`),
  KEY `IDX_EMR_HEADER_ID` (`EMR_HEADER_ID`),
  KEY `IDX_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_VISIT_ID` (`VISIT_ID`),
  KEY `IDX_CONTENT_TYPE` (`CONTENT_TYPE`),
  KEY `IDX_ENCRYPTION_KEY_ID` (`ENCRYPTION_KEY_ID`),
  KEY `IDX_VALIDATION_STATUS` (`VALIDATION_STATUS`),
  KEY `IDX_QUALITY_SCORE` (`QUALITY_SCORE`),
  KEY `IDX_STATUS` (`STATUS`),
  KEY `IDX_CREATED_AT` (`CREATED_AT`),
  KEY `IDX_CLI_EMR_CONTENTS_EMR_HEADER_ID` (`EMR_HEADER_ID`),
  KEY `IDX_CLI_EMR_CONTENTS_PATIENT_ID` (`PATIENT_ID`),
  CONSTRAINT `FK_EMR_CONTENT_ENCRYPTION_KEY` FOREIGN KEY (`ENCRYPTION_KEY_ID`) REFERENCES `sec_encryption_keys` (`ID`),
  CONSTRAINT `FK_EMR_CONTENT_HEADER` FOREIGN KEY (`EMR_HEADER_ID`) REFERENCES `cli_emr_headers` (`ID`),
  CONSTRAINT `FK_EMR_CONTENT_PATIENT` FOREIGN KEY (`PATIENT_ID`) REFERENCES `pat_patients` (`ID`),
  CONSTRAINT `FK_EMR_CONTENT_VISIT` FOREIGN KEY (`VISIT_ID`) REFERENCES `cli_visits` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=223 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='EMR Document Contents';
